import axios, { AxiosRequestConfig } from "axios";
import { useCallback, useEffect, useRef, useState } from "react";
import { useNavigate } from "react-router-dom";

const defaultRequestData={
    url:'/',method:'GET',data:{}
}

function useRequest<T>(options: AxiosRequestConfig) {
    const navigate = useNavigate();
    const [data, setData] = useState<T | null>(null);
    const [error, setError] = useState("");
    const [loaded, setLoaded] = useState(false);

    //取消请求的方法（ref作用：包裹了一个 即使值改变了也不会重新渲染页面）
    const controllerRef = useRef(new AbortController())
    const cancel = () => {
        controllerRef.current.abort();
    }

    const request = useCallback((requestOptions: AxiosRequestConfig) => {
        setData(null)
        setError("")
        setLoaded(false)

        const loginToken = localStorage.getItem("token")
        const headers = loginToken ? { token: loginToken } : {}

        return axios.request<T>({
            url: requestOptions.url,
            method: requestOptions.method,
            signal: controllerRef.current.signal,
            data: requestOptions.data,
            params: requestOptions.params,
            headers: headers
        }).then((response) => {
            setData(response.data);
            return response.data
        }).catch((e: any) => {
            if (e?.response?.status === 403) {
                localStorage.removeItem("token")
                navigate("/account/login")
            }
            setError(e.message || 'unknow error')
            throw new Error(e);
        }).finally(() => { setLoaded(true); })
    }, [navigate, options])

    useEffect(() => {
        request(options)
    }, [options,request])

    return { data, error, loaded, request, cancel };
}

export default useRequest;
